esqlQuery.esql:
FROM metrics-influxdb.otel-*
// Compactions waiting to run (gauge)
| WHERE COALESCE(metrics.storage_compactions_queued, storage_compactions_queued) IS NOT NULL
// Get max queue depth per host and compaction level
| STATS max_queued = MAX(COALESCE(metrics.storage_compactions_queued, storage_compactions_queued))
  BY host.name, COALESCE(attributes.level, "unknown")
// Alert when compaction queue exceeds threshold (e.g. 10)
// Adjust for your environment
| WHERE max_queued >= 10
